const ts = $input.first().json.timestamp;
const d = new Date(ts);

// 上个月月初
const startPrev = new Date(d.getFullYear(), d.getMonth() - 1, 1, 0, 0, 0, 0);
// 本月月初（作为上个月的“排除性结束”边界）
const startThis = new Date(d.getFullYear(), d.getMonth(), 1, 0, 0, 0, 0);
// 上个月月末 23:59:59
const endPrevInclusive = new Date(startThis.getTime() - 1000);

function pad(n){ return String(n).padStart(2, '0'); }
function fmt(dt){
  return `${dt.getFullYear()}-${pad(dt.getMonth()+1)}-${pad(dt.getDate())} ` +
         `${pad(dt.getHours())}:${pad(dt.getMinutes())}:${pad(dt.getSeconds())}`;
}

const monthStart = fmt(startPrev);
const monthEnd = fmt(endPrevInclusive);

return [{
  json: {
    monthStart,
    monthEnd,
    monthStartSql: `TIMESTAMP '${monthStart}'`,
    monthEndSql: `TIMESTAMP '${monthEnd}'`,
  }
}];

// n8n Code node
// Input items: [{json:{retroid:"W92..."}} , ...]

// retroid前三位 -> 机型
const map = {
  W92: 'W942',
  W51: 'W541',
  W52: 'W542',
  W35: 'W335',
};

const counts = {
  W942: 0,
  W541: 0,
  W542: 0,
  W335: 0,
};

for (const item of $input.all()) {
  const r = item.json.retroid;
  if (!r || typeof r !== 'string') continue;

  const prefix3 = r.slice(0, 3);
  const mt = map[prefix3];
  if (mt) counts[mt] += 1;
}

// 输出为多条 items：{ machine_type, total_cnt }
return Object.entries(counts).map(([machine_type, total_cnt]) => ({
  json: { machine_type, total_cnt },
}));

// n8n Code node
// Input: items like { machine_type: "W335", total_cnt: "33082" }

const targets = ['W942', 'W541', 'W542', 'W335'];

// 1) 汇总
const sums = Object.fromEntries(targets.map(t => [t, 0]));
for (const item of $input.all()) {
  const mt = item.json.machine_type;
  if (!targets.includes(mt)) continue;

  const n = Number(item.json.total_cnt ?? 0);
  sums[mt] += Number.isFinite(n) ? n : 0;
}
const grandTotal = targets.reduce((acc, t) => acc + sums[t], 0);

// 2) 上个月月份文本（优先用上游“整理时间格式”节点的 timestamp；没有则用当前时间）
const ts =
  $node?.['整理时间格式']?.json?.timestamp ||
  $node?.['整理时间格式']?.first?.().json?.timestamp ||
  new Date().toISOString();

const d = new Date(ts);
const prev = new Date(d.getFullYear(), d.getMonth() - 1, 1);
const year = prev.getFullYear();
const monthNum = prev.getMonth() + 1;
const monthLabel = `${year}-${String(monthNum).padStart(2, '0')}`;
const reportTitle = `${monthNum}月发货月报`;

function escHtml(s) {
  return String(s)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');
}

const rows = targets.map((mt) => `
  <tr>
    <td style="padding:10px 12px;border-bottom:1px solid #eef2f7;color:#0f172a;">${escHtml(monthLabel)}</td>
    <td style="padding:10px 12px;border-bottom:1px solid #eef2f7;color:#0f172a;font-weight:600;">${escHtml(mt)}</td>
    <td style="padding:10px 12px;border-bottom:1px solid #eef2f7;color:#0f172a;text-align:right;font-variant-numeric:tabular-nums;">
      ${sums[mt].toLocaleString('en-US')}
    </td>
  </tr>
`).join('\n');

const html = `
<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,'PingFang SC','Hiragino Sans GB','Microsoft YaHei',sans-serif;color:#0f172a;">
  <!-- Title (center + color) -->
  <div style="text-align:center;margin:4px 0 14px 0;">
    <div style="font-size:20px;font-weight:900;letter-spacing:0.6px;color:#2563eb;">
      ${escHtml(reportTitle)}
    </div>
    <div style="margin-top:6px;font-size:12px;color:#64748b;">
      统计月份：<span style="font-weight:700;color:#334155;">${escHtml(monthLabel)}</span>
      <span style="margin:0 10px;color:#cbd5e1;">|</span>
      机型范围：${targets.map(escHtml).join(' / ')}
    </div>
  </div>

  <div style="border:1px solid #e2e8f0;border-radius:10px;overflow:hidden;box-shadow:0 1px 2px rgba(15,23,42,0.05);">
    <table style="width:100%;border-collapse:collapse;background:#ffffff;">
      <thead>
        <tr style="background:linear-gradient(180deg,#f8fafc,#f1f5f9);">
          <th style="text-align:left;padding:12px;border-bottom:1px solid #e2e8f0;font-size:13px;color:#334155;">月份</th>
          <th style="text-align:left;padding:12px;border-bottom:1px solid #e2e8f0;font-size:13px;color:#334155;">机型</th>
          <th style="text-align:right;padding:12px;border-bottom:1px solid #e2e8f0;font-size:13px;color:#334155;">发货总数量</th>
        </tr>
      </thead>
      <tbody>
        ${rows}
        <tr style="background:#f8fafc;">
          <td style="padding:12px;border-top:1px solid #e2e8f0;font-weight:800;color:#0f172a;">合计</td>
          <td style="padding:12px;border-top:1px solid #e2e8f0;color:#64748b;">—</td>
          <td style="padding:12px;border-top:1px solid #e2e8f0;text-align:right;font-weight:900;color:#0f172a;font-variant-numeric:tabular-nums;">
            ${grandTotal.toLocaleString('en-US')}
          </td>
        </tr>
      </tbody>
    </table>
  </div>

  <div style="margin-top:10px;font-size:12px;color:#94a3b8;">
    说明：本报表仅统计机型 ${targets.map(escHtml).join(' / ')}；数量为汇总值。
  </div>
</div>
`.trim();

return [{
  json: {
    monthLabel,
    reportTitle,
    sums,
    grandTotal,
    html,
  }
}];
